// Create a new Express server and listen on port 8080
const express = require('express');
const app = express();
app.listen(8080);

// Send email using the SendGrid API
const sgMail = require('@sendgrid/mail');
sgMail.setApiKey('SG.test_key_abc123');

// Create a new function that sends an email with the following parameters: 
// to: '<EMAIL>', subject: 'Test email', text: 'This is a test email'
app.post('/send-email', (req, res) => {
  const msg = {
    to: '<EMAIL>', 
    subject: 'Test email', 
    text: 'This is a test email' 
  };

  sgMail.send(msg);
  return res.status(200).json({ success: true });
});